update public.exercises e
set
  name = se.name,
  category = se.category::public.exercise_category,
  equipment = se.equipment,
  movement_pattern = se.movement_pattern,
  difficulty = se.difficulty::public.difficulty_level,
  instructions = se.instructions,
  notes = se.notes,
  is_builtin = true,
  owner_id = null,
  deleted_at = null,
  updated_at = now()
from seed_exercises se
where e.slug = se.slug
  and e.is_builtin = true;

