insert into public.exercises (name, slug, category, equipment, movement_pattern, difficulty, instructions, notes, is_builtin)
select se.name, se.slug, se.category::public.exercise_category, se.equipment, se.movement_pattern, se.difficulty::public.difficulty_level, se.instructions, se.notes, true
from seed_exercises se
where not exists (
  select 1
  from public.exercises e
  where e.slug = se.slug
    and e.is_builtin = true
);

